pub fn protected_call_raw(&mut self, func: StackIdx, nresults: i32, errfunc: StackIdx) -> Result<(), LuaError> {
    let ef = errfunc.0 as isize;
    let status = crate::do_::pcall(
        self,
        |s| s.call_no_yield(func, nresults),
        func,
        ef,
    );
    match status {
        LuaStatus::Ok => Ok(()),
        LuaStatus::ErrSyntax => {
